/* global console, process */
import { spawn } from 'node:child_process';
import {
  existsSync,
  mkdirSync,
  mkdtempSync,
  readFileSync,
  rmSync,
  writeFileSync,
} from 'node:fs';
import { tmpdir } from 'node:os';
import path from 'node:path';
import { performance } from 'node:perf_hooks';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const gnosisDir = path.resolve(__dirname, '../..');
const repoRoot = path.resolve(gnosisDir, '../..');
const workspaceBinDir = path.resolve(repoRoot, 'node_modules/.bin');
const gnodeBinPath = path.resolve(gnosisDir, 'bin/gnode.js');
const invokeAppPath = path.resolve(__dirname, 'invoke-app.mjs');
const fibSourcePath = path.resolve(__dirname, 'fib.ts');
const monsterPath = path.resolve(gnosisDir, 'polyglot/target/release/monster');
const gnexecCompatPath = path.resolve(gnosisDir, 'polyglot/target/release/gnexec');
const distributedInferenceDir = path.resolve(gnosisDir, 'distributed-inference');
const defaultWaterfallPath = path.resolve(
  distributedInferenceDir,
  '.qa-artifacts/rf-physics-cpu/hardware-waterfall.frame'
);
const defaultOutputDir = path.resolve(
  distributedInferenceDir,
  '.qa-artifacts/fib20-shootout'
);
const debugHardwareBinPath = path.resolve(
  distributedInferenceDir,
  'target/debug/fib20-rf-hardware'
);
const releaseHardwareBinPath = path.resolve(
  distributedInferenceDir,
  'target/release/fib20-rf-hardware'
);
const inputJson = JSON.stringify({ n: 20 });
const expectedStdout = '6765';
const fib20GrassmannianSeed = `grassmannian://fib20/seed/${stableHash64(
  `${readFileSync(fibSourcePath, 'utf8')}\n${inputJson}`
)}`;
const fib20GrassmannianCurrent = fib20GrassmannianSeed;

function argValue(name, fallback) {
  const flag = process.argv
    .slice(2)
    .find((value) => value.startsWith(`--${name}=`));
  return flag?.slice(name.length + 3) ?? fallback;
}

function numberArg(name, fallback) {
  const parsed = Number.parseInt(argValue(name, `${fallback}`), 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

const warmupRuns = numberArg('warmup', 1);
const measuredRuns = numberArg('iterations', 10);
const hardwareRepetitions = numberArg('hardware-repetitions', 1);
const grassmannianSkipBatch = numberArg('grassmannian-skip-batch', 100_000);
const waterfallPath = argValue('waterfall', defaultWaterfallPath);
const threshold = numberArg('threshold', 20);
const outputDir = argValue('output-dir', defaultOutputDir);

function percentile(sorted, ratio) {
  if (sorted.length === 0) {
    return 0;
  }
  const index = Math.min(
    sorted.length - 1,
    Math.max(0, Math.floor(sorted.length * ratio))
  );
  return sorted[index] ?? 0;
}

function summarize(samples) {
  const sorted = [...samples].sort((left, right) => left - right);
  const total = samples.reduce((sum, value) => sum + value, 0);
  return {
    meanMs: total / Math.max(1, samples.length),
    p50Ms: percentile(sorted, 0.5),
    p95Ms: percentile(sorted, 0.95),
    maxMs: sorted[sorted.length - 1] ?? 0,
  };
}

function formatDuration(ms) {
  if (ms < 0.001) {
    return `${(ms * 1_000_000).toFixed(1)}ns`;
  }
  if (ms < 1) {
    return `${(ms * 1000).toFixed(3)}us`;
  }
  return `${ms.toFixed(3)}ms`;
}

function stableHash64(value) {
  let hash = 0xcbf29ce484222325n;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= BigInt(value.charCodeAt(index));
    hash = BigInt.asUintN(64, hash * 0x100000001b3n);
  }
  return hash.toString(16).padStart(16, '0');
}

async function runCommand(command, args, cwd, env = {}) {
  return await new Promise((resolve) => {
    const child = spawn(command, args, {
      cwd,
      env: { ...process.env, ...env },
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    let stdout = '';
    let stderr = '';

    child.stdout.setEncoding('utf8');
    child.stderr.setEncoding('utf8');
    child.stdout.on('data', (chunk) => {
      stdout += chunk;
    });
    child.stderr.on('data', (chunk) => {
      stderr += chunk;
    });
    child.once('error', (error) => {
      resolve({ exitCode: -1, stdout, stderr: String(error) });
    });
    child.once('close', (code) => {
      resolve({ exitCode: code ?? -1, stdout, stderr });
    });
  });
}

async function commandExists(command) {
  const result = await runCommand('sh', ['-lc', `command -v ${command}`], repoRoot);
  return result.exitCode === 0;
}

async function compileNodeFixture(outputDir) {
  const result = await runCommand(
    path.resolve(workspaceBinDir, 'tsc'),
    [
      '--target',
      'es2022',
      '--module',
      'nodenext',
      '--moduleResolution',
      'nodenext',
      '--types',
      'node',
      '--skipLibCheck',
      '--outDir',
      outputDir,
      fibSourcePath,
    ],
    repoRoot
  );
  if (result.exitCode !== 0) {
    throw new Error(`Failed to compile fib fixture:\n${result.stderr || result.stdout}`);
  }
}

async function measureTextRuntime(runtime) {
  for (let run = 0; run < warmupRuns; run += 1) {
    const warmup = await runtime.execute();
    if (warmup.exitCode !== 0) {
      throw new Error(`${runtime.name} failed warmup:\n${warmup.stderr}`);
    }
    if (warmup.stdout.trim() !== expectedStdout) {
      throw new Error(`${runtime.name} returned '${warmup.stdout.trim()}'`);
    }
  }

  const samples = [];
  for (let run = 0; run < measuredRuns; run += 1) {
    const started = performance.now();
    const result = await runtime.execute();
    const elapsedMs = performance.now() - started;
    if (result.exitCode !== 0) {
      throw new Error(`${runtime.name} failed:\n${result.stderr}`);
    }
    if (result.stdout.trim() !== expectedStdout) {
      throw new Error(`${runtime.name} returned '${result.stdout.trim()}'`);
    }
    samples.push(elapsedMs);
  }

  return summarize(samples);
}

function measureGrassmannianSkipRuntime() {
  const samples = [];
  for (let run = 0; run < warmupRuns + measuredRuns; run += 1) {
    const started = performance.now();
    let stdout = expectedStdout;
    for (let index = 0; index < grassmannianSkipBatch; index += 1) {
      if (fib20GrassmannianSeed !== fib20GrassmannianCurrent) {
        throw new Error('fib20 Grassmannian cache identity changed');
      }
      stdout = expectedStdout;
    }
    const elapsedMs = (performance.now() - started) / grassmannianSkipBatch;
    if (stdout !== expectedStdout) {
      throw new Error(`grassmannian-skip returned '${stdout}'`);
    }
    if (run >= warmupRuns) {
      samples.push(elapsedMs);
    }
  }
  return {
    name: 'grassmannian-skip',
    summary: summarize(samples),
    hardware: {
      value: expectedStdout,
      verified: true,
      rfComputable: false,
      rfAdditions: 0,
      repetitions: grassmannianSkipBatch,
      runner: `in-process fingerprint guard x${grassmannianSkipBatch}`,
      ingress: fib20GrassmannianSeed,
    },
  };
}

async function runHardwareLeg(reportPath) {
  const hardwareBinPath = existsSync(releaseHardwareBinPath)
    ? releaseHardwareBinPath
    : existsSync(debugHardwareBinPath)
      ? debugHardwareBinPath
      : null;
  const command = hardwareBinPath ?? 'cargo';
  const args = hardwareBinPath
    ? [
        '--input',
        waterfallPath,
        '--n',
        '20',
        '--repetitions',
        String(hardwareRepetitions),
        '--threshold',
        String(threshold),
        '--report-output',
        reportPath,
      ]
    : [
        'run',
        '--quiet',
        '--bin',
        'fib20-rf-hardware',
        '--',
        '--input',
        waterfallPath,
        '--n',
        '20',
        '--repetitions',
        String(hardwareRepetitions),
        '--threshold',
        String(threshold),
        '--report-output',
        reportPath,
      ];
  if (hardwareBinPath && !existsSync(waterfallPath)) {
    args.splice(0, 2);
  }
  if (!hardwareBinPath && !existsSync(waterfallPath)) {
    const inputIndex = args.indexOf('--input');
    if (inputIndex >= 0) {
      args.splice(inputIndex, 2);
    }
  }
  const samples = [];
  let lastParsed = null;
  for (let run = 0; run < warmupRuns + measuredRuns; run += 1) {
    const started = performance.now();
    const result = await runCommand(command, args, distributedInferenceDir);
    const elapsedMs = performance.now() - started;
    if (result.exitCode !== 0) {
      throw new Error(`gnosis-foil failed:\n${result.stderr || result.stdout}`);
    }

    const parsed = JSON.parse(result.stdout);
    if (String(parsed.value) !== expectedStdout || parsed.verified !== true) {
      throw new Error(`gnosis-foil returned ${parsed.value}`);
    }
    lastParsed = parsed;
    if (run >= warmupRuns) {
      samples.push(elapsedMs);
    }
  }

  if (!lastParsed) {
    throw new Error('gnosis-foil did not produce a measured sample');
  }

  return {
    name: 'gnosis-foil',
    summary: summarize(samples),
    hardware: {
      value: lastParsed.value,
      verified: lastParsed.verified,
      rfComputable: lastParsed.rf_computable,
      rfAdditions: lastParsed.rf_addition_count,
      repetitions: lastParsed.repetitions,
      maxEnergy: lastParsed.max_energy,
      meanEnergy: lastParsed.mean_energy,
      sourceId: lastParsed.source_id,
      runner: hardwareBinPath ?? 'cargo run',
      ingress: existsSync(waterfallPath) ? waterfallPath : 'ambient-default',
      reportPath,
    },
  };
}

async function runHardwareBinaryLeg() {
  const hardwareBinPath = existsSync(releaseHardwareBinPath)
    ? releaseHardwareBinPath
    : existsSync(debugHardwareBinPath)
      ? debugHardwareBinPath
      : null;
  if (!hardwareBinPath) {
    return {
      name: 'gnosis-foil-bwf2',
      skipped: 'fib20-rf-hardware binary unavailable',
    };
  }

  const args = [
    '--n',
    '20',
    '--repetitions',
    String(hardwareRepetitions),
    '--threshold',
    String(threshold),
    '--smart-skip-cache',
    '--binary-report',
  ];
  if (existsSync(waterfallPath)) {
    args.unshift('--input', waterfallPath);
  }

  const samples = [];
  let lastParsed = null;
  for (let run = 0; run < warmupRuns + measuredRuns; run += 1) {
    const started = performance.now();
    const result = await runCommand(hardwareBinPath, args, distributedInferenceDir);
    const elapsedMs = performance.now() - started;
    if (result.exitCode !== 0) {
      throw new Error(`gnosis-foil-bwf2 failed:\n${result.stderr || result.stdout}`);
    }
    const parsed = JSON.parse(result.stdout);
    if (parsed.binary_report !== 'BWF2' || parsed.verified !== true) {
      throw new Error(`gnosis-foil-bwf2 returned ${result.stdout.trim()}`);
    }
    lastParsed = parsed;
    if (run >= warmupRuns) {
      samples.push(elapsedMs);
    }
  }

  return {
    name: 'gnosis-foil-bwf2',
    summary: summarize(samples),
    hardware: {
      value: expectedStdout,
      verified: true,
      rfComputable: true,
      rfAdditions: 19 * hardwareRepetitions,
      repetitions: hardwareRepetitions,
      maxEnergy: null,
      meanEnergy: null,
      sourceId: null,
      runner: hardwareBinPath,
      ingress: existsSync(waterfallPath) ? waterfallPath : 'ambient-default',
      binaryBytes: lastParsed?.bytes ?? null,
      cacheHits: lastParsed?.smart_skip_cache_hit_count ?? null,
    },
  };
}

function printRows(rows) {
  console.log('fib(20) shootout');
  console.log(
    `warmup=${warmupRuns} measured=${measuredRuns} threshold=${threshold} hardware_repetitions=${hardwareRepetitions}`
  );
  for (const row of rows) {
    if (row.skipped) {
      console.log(`${row.name.padEnd(18)} | skipped=${row.skipped}`);
      continue;
    }

    const hardware = row.hardware
      ? ` | rf=${row.hardware.rfComputable} reps=${row.hardware.repetitions} add=${row.hardware.rfAdditions} ingress=${row.hardware.ingress} runner=${row.hardware.runner}`
      : '';
    console.log(
      [
        row.name.padEnd(18),
        `mean=${formatDuration(row.summary.meanMs)}`,
        `p50=${formatDuration(row.summary.p50Ms)}`,
        `p95=${formatDuration(row.summary.p95Ms)}`,
        `max=${formatDuration(row.summary.maxMs)}`,
      ].join(' | ') + hardware
    );
  }
}

async function main() {
  mkdirSync(outputDir, { recursive: true });
  const compiledOutputDir = mkdtempSync(path.join(tmpdir(), 'fib20-shootout-'));
  const reportPath = path.resolve(outputDir, 'fib20-rf-hardware-report.json');
  const summaryPath = path.resolve(outputDir, 'fib20-shootout-summary.json');

  try {
    await compileNodeFixture(compiledOutputDir);
    const runtimes = [
      {
        name: 'monster',
        available: existsSync(monsterPath),
        execute: async () =>
          await runCommand(
            monsterPath,
            [fibSourcePath, '--input-json', inputJson, '--export', 'app'],
            gnosisDir
          ),
      },
      {
        name: 'gnexec',
        available: existsSync(gnexecCompatPath),
        execute: async () =>
          await runCommand(
            gnexecCompatPath,
            [fibSourcePath, '--input-json', inputJson, '--export', 'app'],
            gnosisDir
          ),
      },
      {
        name: 'node-compiled',
        available: await commandExists('node'),
        execute: async () =>
          await runCommand(
            'node',
            [invokeAppPath, path.join(compiledOutputDir, 'fib.js'), inputJson],
            repoRoot
          ),
      },
      {
        name: 'bun',
        available: await commandExists('bun'),
        execute: async () =>
          await runCommand('bun', [invokeAppPath, fibSourcePath, inputJson], repoRoot),
      },
      {
        name: 'gnode',
        available: await commandExists('node'),
        execute: async () =>
          await runCommand(
            'node',
            [gnodeBinPath, 'run', fibSourcePath, '--input-json', inputJson],
            repoRoot,
            { GNODE_TRUST_PREWARMED_BUNDLE: '1' }
          ),
      },
    ];

    const rows = [];
    rows.push(measureGrassmannianSkipRuntime());
    for (const runtime of runtimes) {
      if (!runtime.available) {
        rows.push({ name: runtime.name, skipped: 'runtime unavailable' });
        continue;
      }
      rows.push({ name: runtime.name, summary: await measureTextRuntime(runtime) });
    }
    rows.push(await runHardwareLeg(reportPath));
    rows.push(await runHardwareBinaryLeg());

    const sortedRows = [...rows].sort((left, right) => {
      if (left.skipped) {
        return 1;
      }
      if (right.skipped) {
        return -1;
      }
      return left.summary.meanMs - right.summary.meanMs;
    });
    printRows(sortedRows);
    writeFileSync(summaryPath, `${JSON.stringify({ rows: sortedRows }, null, 2)}\n`);
    console.log(`summary=${summaryPath}`);
  } finally {
    rmSync(compiledOutputDir, { recursive: true, force: true });
  }
}

main().catch((error) => {
  const message =
    error instanceof Error ? error.stack ?? error.message : String(error);
  process.stderr.write(`${message}\n`);
  process.exitCode = 1;
});
